          {i, 1, ActiveBlobs}
        ]/ActiveBlobs,

        (* Optimization via water-filling *)
        OptimalDistribution = WaterFillingAlgorithm[
          ChannelGains → Eigenvalues[ProbabilityMatrix],
          PowerConstraint → TotalPower
        ]
      },

      Result → Bandwidth × (Log₂[1 + SNR] + ε_quantum)
    ]
  ]
